Create `ShipmentTracker/Endpoints/ShipmentEndpoints.cs`:
```csharp
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Data;

namespace ShipmentTracker.Endpoints;

public static class ShipmentEndpoints
{
    public static void MapShipmentEndpoints(this WebApplication app)
    {
        var group = app.MapGroup("api/shipments").RequireAuthorization();

        group.MapGet("", async (ApplicationDbContext db) =>
        {
            return await db.Shipments.Select(e => new Shipment
            {
                Id = e.Id,
                TrackingNumber = e.TrackingNumber,
                Origin = e.Origin,
                Destination = e.Destination,
                Status = e.Status,
                ShippedDate = e.ShippedDate,
                EstimatedDelivery = e.EstimatedDelivery,
                ActualDelivery = e.ActualDelivery,
                CustomerEmail = e.CustomerEmail,
                Description = e.Description
            }).ToListAsync();
        });

        group.MapGet("track/{trackingNumber}", async (string trackingNumber, ApplicationDbContext db) =>
        {
            var entity = await db.Shipments.FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
            if (entity is null) return Results.NotFound();
            return Results.Ok(new Shipment
            {
                Id = entity.Id,
                TrackingNumber = entity.TrackingNumber,
                Origin = entity.Origin,
                Destination = entity.Destination,
                Status = entity.Status,
                ShippedDate = entity.ShippedDate,
                EstimatedDelivery = entity.EstimatedDelivery,
                ActualDelivery = entity.ActualDelivery,
                CustomerEmail = entity.CustomerEmail,
                Description = entity.Description
            });
        });

        group.MapGet("customer/{email}", async (string email, ApplicationDbContext db) =>
        {
            return await db.Shipments
                .Where(s => s.CustomerEmail == Uri.UnescapeDataString(email))
                .Select(e => new Shipment
                {
                    Id = e.Id,
                    TrackingNumber = e.TrackingNumber,
                    Origin = e.Origin,
                    Destination = e.Destination,
                    Status = e.Status,
                    ShippedDate = e.ShippedDate,
                    EstimatedDelivery = e.EstimatedDelivery,
                    ActualDelivery = e.ActualDelivery,
                    CustomerEmail = e.CustomerEmail,
                    Description = e.Description
                }).ToListAsync();
        });

        group.MapPut("{id}/status", async (int id, ShipmentStatus status, ApplicationDbContext db) =>
        {
            var entity = await db.Shipments.FindAsync(id);
            if (entity is null) return Results.NotFound();
            entity.Status = status;
            if (status == ShipmentStatus.Delivered)
                entity.ActualDelivery = DateTime.UtcNow;
            await db.SaveChangesAsync();
            return Results.NoContent();
        });
    }
}
```

