@page "/shipments"
@attribute [Microsoft.AspNetCore.Authorization.Authorize]
@inject IShipmentService ShipmentService

<PageTitle>Dispatcher Dashboard</PageTitle>

<h1>Dispatcher Dashboard</h1>

<div class="row mb-3">
    <div class="col-md-4">
        <input type="text" class="form-control" placeholder="Filter by destination..."
               @bind="filterText" @bind:event="oninput" />
    </div>
    <div class="col-md-3">
        <select class="form-select" @bind="statusFilter">
            <option value="">All Statuses</option>
            @foreach (var s in Enum.GetValues<ShipmentStatus>())
            {
                <option value="@s">@s</option>
            }
        </select>
    </div>
</div>

@if (shipments is null)
{
    <p><em>Loading shipments...</em></p>
}
else if (!FilteredShipments.Any())
{
    <p>No shipments match your filter.</p>
}
else
{
    <table class="table table-striped table-hover">
        <thead>
            <tr>
                <th>Tracking #</th>
                <th>Origin</th>
                <th>Destination</th>
                <th>Status</th>
                <th>Est. Delivery</th>
                <th>Actions</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var shipment in FilteredShipments)
            {
                <tr>
                    <td>@shipment.TrackingNumber</td>
                    <td>@shipment.Origin</td>
                    <td>@shipment.Destination</td>
                    <td><span class="badge @GetStatusBadge(shipment.Status)">@shipment.Status</span></td>
                    <td>@shipment.EstimatedDelivery.ToString("MMM dd, yyyy")</td>
                    <td>
                        <select class="form-select form-select-sm" style="width: auto; display: inline-block;"
                                value="@shipment.Status"
                                @onchange="(e) => UpdateStatus(shipment, e)">
                            @foreach (var s in Enum.GetValues<ShipmentStatus>())
                            {
                                <option value="@s">@s</option>
                            }
                        </select>
                    </td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<Shipment>? shipments;
    private string filterText = string.Empty;
    private string statusFilter = string.Empty;

    private IEnumerable<Shipment> FilteredShipments => shipments!
        .Where(s => string.IsNullOrEmpty(filterText) || s.Destination.Contains(filterText, StringComparison.OrdinalIgnoreCase))
        .Where(s => string.IsNullOrEmpty(statusFilter) || s.Status.ToString() == statusFilter);

    protected override async Task OnInitializedAsync()
    {
        shipments = await ShipmentService.GetAllShipmentsAsync();
    }

    private async Task UpdateStatus(Shipment shipment, ChangeEventArgs e)
    {
        if (Enum.TryParse<ShipmentStatus>(e.Value?.ToString(), out var newStatus))
        {
            await ShipmentService.UpdateShipmentStatusAsync(shipment.Id, newStatus);
            shipment.Status = newStatus;
            if (newStatus == ShipmentStatus.Delivered)
                shipment.ActualDelivery = DateTime.UtcNow;
        }
    }

    private static string GetStatusBadge(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Delayed => "bg-danger",
        _ => "bg-secondary"
    };
}

@page "/track"
@attribute [Microsoft.AspNetCore.Authorization.Authorize]
@inject IShipmentService ShipmentService

<PageTitle>Track Shipment</PageTitle>

<h1>Track a Shipment</h1>

<div class="row mb-4">
    <div class="col-md-6">
        <div class="input-group">
            <input type="text" class="form-control" placeholder="Enter tracking number (e.g., SHP-001-2026)"
                   @bind="trackingNumber" @bind:event="oninput"
                   @onkeyup="HandleKeyUp" />
            <button class="btn btn-primary" @onclick="Search" disabled="@searching">
                @(searching ? "Searching..." : "Track")
            </button>
        </div>
    </div>
</div>

@if (searched && shipment is null)
{
    <div class="alert alert-warning">No shipment found with tracking number <strong>@searchedNumber</strong>.</div>
}
else if (shipment is not null)
{
    <div class="card">
        <div class="card-header">
            <h5 class="mb-0">Shipment @shipment.TrackingNumber</h5>
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6">
                    <dl>
                        <dt>Description</dt>
                        <dd>@shipment.Description</dd>
                        <dt>Origin</dt>
                        <dd>@shipment.Origin</dd>
                        <dt>Destination</dt>
                        <dd>@shipment.Destination</dd>
                    </dl>
                </div>
                <div class="col-md-6">
                    <dl>
                        <dt>Status</dt>
                        <dd><span class="badge @GetStatusBadge(shipment.Status) fs-6">@shipment.Status</span></dd>
                        <dt>Shipped Date</dt>
                        <dd>@shipment.ShippedDate.ToString("MMM dd, yyyy")</dd>
                        <dt>Estimated Delivery</dt>
                        <dd>@shipment.EstimatedDelivery.ToString("MMM dd, yyyy")</dd>
                        @if (shipment.ActualDelivery.HasValue)
                        {
                            <dt>Actual Delivery</dt>
                            <dd>@shipment.ActualDelivery.Value.ToString("MMM dd, yyyy")</dd>
                        }
                    </dl>
                </div>
            </div>
        </div>
    </div>
}

@code {
    private string trackingNumber = string.Empty;
    private string searchedNumber = string.Empty;
    private Shipment? shipment;
    private bool searched;
    private bool searching;

    private async Task Search()
    {
        if (string.IsNullOrWhiteSpace(trackingNumber)) return;
        searching = true;
        searched = false;
        shipment = null;

        shipment = await ShipmentService.GetShipmentByTrackingNumberAsync(trackingNumber.Trim());
        searchedNumber = trackingNumber.Trim();
        searched = true;
        searching = false;
    }

    private async Task HandleKeyUp(KeyboardEventArgs e)
    {
        if (e.Key == "Enter") await Search();
    }

    private static string GetStatusBadge(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Delayed => "bg-danger",
        _ => "bg-secondary"
    };
}

